const express = require('express');
const twilio = require('twilio')(accountSid, authToken);
const app = express();

app.use(express.json());

// Generate random 6-digit code and send via SMS
app.post('/sendCode', (req, res) => {
  const userId = req.body.userId;
  const code = Math.floor(Math.random() * 1000000);
  twilio.messages.create({
    body: `Your verification code is ${code}.`,
    to: userId,
    from: '+1234567890' // Replace with your Twilio number
  });
  res.json({ message: 'Code sent successfully.' });
});

// Verify user input against stored code in memory
app.post('/verify', (req, res) => {
  const userId = req.body.userId;
  const enteredCode = req.body.code;
  if (enteredCode === code) {
    // User has successfully verified their identity
    res.json({ message: 'Verification successful.' });
  } else {
    // User has not successfully verified their identity
    res.status(401).json({ message: 'Invalid verification code.' });
  }
});